// src/pages/ngo/admin/RegisterPage.jsx
import { useState } from "react";
import { useToast } from "../../../context/ToastContext";
import PageHeader   from "../../../components/shared/PageHeader";
import DataTable    from "../../../components/shared/DataTable";
import Badge        from "../../../components/shared/Badge";
import { ngos }     from "../../../data/mockData";

export default function RegisterPage() {
  const toast = useToast();
  const [form, setForm] = useState({ name:"", focus:"", email:"", website:"", desc:"", wallet:"" });
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  return (
    <div>
      <PageHeader title="Register NGO" desc="Enroll a new NGO on the blockchain ledger" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group"><label>Organization Name</label><input value={form.name} onChange={upd("name")} placeholder="Full legal name" /></div>
            <div className="form-group">
              <label>Focus Area</label>
              <select value={form.focus} onChange={upd("focus")}>
                <option value="">Select...</option>
                <option>Environment</option><option>Education</option><option>Healthcare</option>
                <option>Poverty Relief</option><option>Disaster Relief</option><option>Other</option>
              </select>
            </div>
            <div className="form-group"><label>Admin Email</label><input value={form.email} onChange={upd("email")} type="email" placeholder="admin@ngo.org" /></div>
            <div className="form-group"><label>Website</label><input value={form.website} onChange={upd("website")} placeholder="https://ngo.org" /></div>
            <div className="form-group"><label>Wallet Address</label><input value={form.wallet} onChange={upd("wallet")} placeholder="0x..." /></div>
            <div className="form-group"><label>Description</label><textarea value={form.desc} onChange={upd("desc")} placeholder="Mission and activities..." /></div>
            <div className="form-actions">
              <button className="btn btn-secondary">Clear</button>
              <button className="btn btn-primary" onClick={() => toast("NGO registration submitted for verification", "success")}>Register NGO</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>NGO Registry</div>
          <DataTable
            columns={[
              { key:"id",       label:"ID",     mono:true },
              { key:"name",     label:"NGO"               },
              { key:"focus",    label:"Focus"             },
              { key:"verified", label:"Status", render:(r) => r.verified ? <Badge type="green">Verified</Badge> : <Badge type="red">Pending</Badge> },
            ]}
            data={ngos}
          />
        </div>
      </div>
    </div>
  );
}
